urlset:
{% for post in posts %}

  {# Use post.permalink directly to avoid double-encoding %25 since post.permalink is already encoded #}
  {{ post.permalink }}
  {% if post.updated %}
  {{ post.updated | formatDate }}
  {% elif post.date %}
  {{ post.date | formatDate }}
  {% endif %}
  monthly
  0.6

{% endfor %}


  {{ config.url }}
  {{ sNow | formatDate }}
  daily
  1.0


{% for tag in tags %}

  {{ tag.permalink }}
  {{ sNow | formatDate }}
  weekly
  0.2

{% endfor %}

{% for cat in categories %}

  {{ cat.permalink }}
  {{ sNow | formatDate }}
  weekly
  0.2

{% endfor %}
